## Attachment Discovery

### Finding Referenced Files
```rust
/// Scan message content for file references
fn discover_attachments(message: &NormalizedMessage, workspace: &Path) -> Vec<AttachmentRef> {
    let mut refs = Vec::new();

    // Pattern 1: Markdown image syntax ![alt](path)
    let img_regex = Regex::new(r"!\[([^\]]*)\]\(([^)]+)\)").unwrap();
    for cap in img_regex.captures_iter(&message.content) {
        let path = cap.get(2).unwrap().as_str();
        if let Some(resolved) = resolve_path(path, workspace) {
            refs.push(AttachmentRef {
                original_ref: path.to_string(),
                resolved_path: resolved,
                ref_type: RefType::MarkdownImage,
            });
        }
    }

    // Pattern 2: File paths in code blocks
    let path_regex = Regex::new(r#"(?:^|\s|["'])(/[^\s"']+\.(png|jpg|jpeg|gif|pdf|svg|txt|md))"#).unwrap();
    for cap in path_regex.captures_iter(&message.content) {
        let path = cap.get(1).unwrap().as_str();
        if let Some(resolved) = resolve_path(path, workspace) {
            refs.push(AttachmentRef {
                original_ref: path.to_string(),
                resolved_path: resolved,
                ref_type: RefType::AbsolutePath,
            });
        }
    }

    // Pattern 3: Agent-specific attachment markers
    // Claude Code: <attachment path="...">
    // Cursor: "file://..."
    // etc.

    refs
}

/// Resolve relative/absolute paths to actual files
fn resolve_path(path: &str, workspace: &Path) -> Option<PathBuf> {
    let path_buf = PathBuf::from(path);

    // Try absolute path first
    if path_buf.is_absolute() && path_buf.exists() {
        return Some(path_buf);
    }

    // Try relative to workspace
    let relative = workspace.join(&path_buf);
    if relative.exists() {
        return Some(relative);
    }

    // Try relative to message source
    // ...

    None
}
